var userConnection = Get<UserConnection>("UserConnection");
var log = new CustomLog(userConnection, "Scheduler_AddVPNGroupMembers");

var lineDetail = new LineDetail(UserConnection);
var CRMService = new CRMService(UserConnection);
List<string> errorList = new List<string>();

try {
    var linesForAddVPNToday = lineDetail.GetLinesAddVPNGroupMember();
    if(linesForAddVPNToday.Count == 0) {
        log.AddMessage("There is currently no data to process", true);
        return true;
    }

    int totalRecord = linesForAddVPNToday.Count;
    log.AddMessage($"There are {totalRecord} lines that will be processed at this time", true);

    List<Guid> submissionGroup = linesForAddVPNToday
        .GroupBy(item => item.SubmissionId)
        .Select(item => item.FirstOrDefault().SubmissionId)
        .ToList();

    foreach(Guid submissionId in submissionGroup) {
        var lines = linesForAddVPNToday.Where(item => item.SubmissionId == submissionId).ToList();
        var processLine = new List<LineDetail>();

        foreach(var line in lines) {
            processLine.Add(line);
            
            if(processLine.Count == 11) {
                string customerName = processLine.FirstOrDefault().CustomerName;
                string serialNumber = processLine.FirstOrDefault().SerialNumber;
                string msisdnList = string.Join(", ", processLine.Select(item => item.MSISDN).ToArray());
                
                log.AddMessage($"Total line to be processed: {processLine.Count}.{Environment.NewLine}Serial Number: {serialNumber}. MSISDN: {msisdnList}", true);

                try {
                    var addVPN = CRMService.AddVPNGroupMembers(processLine).GetAwaiter().GetResult();
                    if(addVPN != null) {
                        string orderId = addVPN.ResultOfOperationReply.orderId;
                        string transactionId = addVPN.ResultOfOperationReply.transactionId;

                        log.AddMessage($"AddVPNGroupMembers Success: {Environment.NewLine}Order ID: {orderId} Transaction ID: {transactionId}{Environment.NewLine}{JsonConvert.SerializeObject(addVPN, Formatting.Indented)}", true);

                        foreach(var item in processLine) {
                            new Update(UserConnection, "DgLineDetail")
                                .Set("DgAddVPNGroupMember", Column.Parameter(true))
                                .Where("Id").IsEqual(Column.Parameter(item.Id))
                                .Execute();

                            string remark = $"{item.MSISDN} added to VPN Group Member. Order ID: {orderId} Transaction ID: {transactionId}";
                            new Insert(UserConnection)
                                .Into("DgHistorySubmission")
                                .Set("CreatedOn", Column.Parameter(DateTime.UtcNow))
                                .Set("CreatedById", Column.Parameter(UserConnection.CurrentUser.ContactId))
                                .Set("DgSubmissionId", Column.Parameter(item.SubmissionId))
                                .Set("DgOpsId", Column.Parameter(LookupConst.Ops.ADDVPN))
                                .Set("DgSectionId", Column.Parameter(LookupConst.Section.CRA_LINE))
                                .Set("DgRemark", Column.Parameter(remark))
                            .Execute();
                        }
                    }
                } catch(Exception e) {
                    errorList.Add(e.ToString());
                    log.AddMessage($"AddVPNGroupMembers Fail: {Environment.NewLine}{e.ToString()}", true);

                    if(e.Message.Contains("20087: ")) {
                        SendEmail(customerName, serialNumber, msisdnList, e.Message);
                    }
                } finally {
                    processLine.Clear();
                }
            }
        }

        if(processLine.Count > 0) {
            string customerName = processLine.FirstOrDefault().CustomerName;
            string serialNumber = processLine.FirstOrDefault().SerialNumber;
            string msisdnList = string.Join(", ", processLine.Select(item => item.MSISDN).ToArray());
            
            log.AddMessage($"Total line to be processed: {processLine.Count}.{Environment.NewLine}Serial Number: {serialNumber}. MSISDN: {msisdnList}", true);
            
            try {
                var addVPN = CRMService.AddVPNGroupMembers(processLine).GetAwaiter().GetResult();
                if(addVPN != null) {
                    string orderId = addVPN.ResultOfOperationReply.orderId;
                    string transactionId = addVPN.ResultOfOperationReply.transactionId;

                    log.AddMessage($"AddVPNGroupMembers Success: {Environment.NewLine}Order ID: {orderId} Transaction ID: {transactionId}{Environment.NewLine}{JsonConvert.SerializeObject(addVPN, Formatting.Indented)}", true);

                    foreach(var item in processLine) {
                        new Update(UserConnection, "DgLineDetail")
                            .Set("DgAddVPNGroupMember", Column.Parameter(true))
                            .Where("Id").IsEqual(Column.Parameter(item.Id))
                            .Execute();

                        string remark = $"{item.MSISDN} added to VPN Group Member. Order ID: {orderId} Transaction ID: {transactionId}";
                        new Insert(UserConnection)
                            .Into("DgHistorySubmission")
                            .Set("CreatedOn", Column.Parameter(DateTime.UtcNow))
                            .Set("CreatedById", Column.Parameter(UserConnection.CurrentUser.ContactId))
                            .Set("DgSubmissionId", Column.Parameter(item.SubmissionId))
                            .Set("DgOpsId", Column.Parameter(LookupConst.Ops.ADDVPN))
                            .Set("DgSectionId", Column.Parameter(LookupConst.Section.CRA_LINE))
                            .Set("DgRemark", Column.Parameter(remark))
                        .Execute();
                    }
                }
            } catch(Exception e) {
                errorList.Add(e.ToString());
                log.AddMessage($"AddVPNGroupMembers Fail: {Environment.NewLine}{e.ToString()}", true);

                if(e.Message.Contains("20087: ")) {
                    SendEmail(customerName, serialNumber, msisdnList, e.Message);
                }
            } finally {
                processLine.Clear();
            }
        }
    }

    if(errorList.Count > 0) {
        Set("Message", string.Join($"{Environment.NewLine}{Environment.NewLine}", errorList.ToArray()));
    }
} catch (Exception e) {
    Set("Message", e.Message);
    log.AddMessage(e.ToString(), true);
} finally {
    log.SaveToFile();
}

return true;

